#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int A[N], B[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        for (int i = 0; i < N; i++) {
            scanf("%d", &B[i]);
        }
        int minRemainder = A[0] % B[0];
        int totalOperations = 0;
        for (int i = 0; i < N; i++) {
            int remainder = A[i] % B[i];
            if (remainder < minRemainder) {
                minRemainder = remainder;
            }
        }
        for (int i = 0; i < N; i++) {
            int operations = (A[i] % B[i]) - minRemainder;
            if (operations < 0) {
                operations += B[i];
            }
            totalOperations += operations;
        }
        printf("%d\n", totalOperations);
    }
    return 0;
}

